import{_ as e,o as p,c as t,j as r,a as b,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const x=JSON.parse('{"title":"现实投掷技巧","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/运动类/现实投掷技巧.md","filePath":"4.资源分区/6.技艺及称号/运动类/现实投掷技巧.md"}'),n={name:"4.资源分区/6.技艺及称号/运动类/现实投掷技巧.md"};function o(_,a,d,l,i,c){return p(),t("div",null,[...a[0]||(a[0]=[r("h1",{id:"现实投掷技巧",tabindex:"-1"},[b("现实投掷技巧 "),r("a",{class:"header-anchor",href:"#现实投掷技巧","aria-label":'Permalink to "现实投掷技巧"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调019")])])],-1),s('<h1 id="现实投掷技巧-1" tabindex="-1">现实投掷技巧 <a class="header-anchor" href="#现实投掷技巧-1" aria-label="Permalink to &quot;现实投掷技巧&quot;">​</a></h1><p>现实投掷技巧</p><p>投掷作为人类历史上最古老的一门战斗与运动技术，在手边没有远程器械时，人们所能依靠的只有自己的双臂。</p><p>由于是现实中存在的技术，因此也可以使用xp进行购买，这视为你通过锻炼自行掌握了这门技术。</p><p>瞄准 500或2xp<br> 让你的的眼睛、投掷物，目标点对成一线。尽管很多新手会忽视，但这一投掷前的动作必不可少。<br> 当目标在你的基础投掷射程内时，你可以以花招动作预先瞄准目标，然后在下一次投掷攻击中视为正常进行了一次瞄准，且已进行了一轮瞄准。</p><p>弓形蓄力 500或2xp<br> 以左脚为支撑点，身体大幅度后仰成弓形，将身体正面的肌肉彻底拉长，为你的投掷增添无与伦比的爆发力。<br> 以一个花招动作做出弓形蓄力姿态，下一次投掷攻击获得2点高速。</p><p>二重蓄力 D+500或10xp<br> 前提：弓形蓄力<br> 后退是为了更好的前进。二重蓄力是投掷的一种进阶技法，它让你以身体为弓，压榨你浑身肌肉骨骼的潜力到极致。其结果便是，使你的投掷物以堪比炮弹的速度射出。<br> 二重蓄力是一个迅捷动作，且必须结合在弓形蓄力中使用，你的身体素质将决定了蓄力强度，此次攻击将附带等同耐力附加成功数的技艺加值。<br> 若你使用的是重武器，它可以使你的下次投掷攻击附带击退/击倒效果，DC为伤害数，反射豁免，失败则对方承受失败数/米的击退或者直接被击倒。你需要在检定前宣言击倒还是击退。<br> 若你使用的是轻武器，它可以使你的下次投掷攻击附带【贯穿】效果。</p><p>转身投 D+500或10xp<br> 古代奥运会项目残留下来的技巧，利用身体的协调与惯性来强化投掷的力道。<br> 以一个移动动作让身体原地绕圈旋转，移动动作维持。每旋转一圈，你的下一次投掷攻击就获得3点附加成功的技艺加值，可叠加，上限三圈，旋转次数不受轮数限制，这意味着最多可以在AP足够的前提下一轮内旋转三圈。<br> 当你结束旋转投状态后，你将因晕头转向而受到持续轮数的晕眩点数，正常豁免。</p><p>助跑 D+500或10xp<br> 若你在攻击前移动过一段距离，则你的此次投掷攻击的基础射程提高15米，并可无视最多3点射程减值。</p><p>飞刀弹幕 250或1xp<br> 当你使用轻武器投掷专业时，你可以同时持有两把武器进行投掷。这不享受武器伤害或特性加成，仅可以造成多次攻击减值。<br> 该技能可重复购买，每次购买可使多次攻击减值+1，上限为你运动等级的一半。</p><p>飞刀弹幕EX 500或2xp<br> 当你使用轻武器投掷专业时，你可以同时持有两把武器进行投掷。你在投掷时同时拥有两把武器的特性，伤害取高不叠加。该效果不适用于一次购买获得多件的武器。<br> 该技能可重复购买，重复购买时价格提升为1250或5xp，每次购买可多拥有一把投掷武器的特性，上限为你运动等级的一半。</p><p>制作投器 500或2xp<br> 轮回世界里你的身旁并不总是具有称手的投掷物，因此你学会了自行制作简易投掷武器的技巧。这些武器默认0L，射程10米，造成穿刺伤害。<br> 武器的原材料一般使用坚固的木、石、骨等等，这些在自然环境中很容易获得。一个小时内可以累计做出5件轻武器或者1件重武器。<br> 当你制作飞镖、小刀等轻型投掷武器时，他们额外获得2点破甲。<br> 当你制作投枪、投锤等重型投掷武器时，他们额外获得2点威猛。</p><p>制作投器EX D+500或10xp<br> （可由制作投器差价升级）<br> 前提：手艺3<br> 手艺高超的你不再满足于制作简易武器，只要身边有趁手的工具和足够的材料，你总能制作出精致的投掷武器。<br> 你可以选择现实武器武器模板中的武器（匕首，飞锤，短矛，回力标等）来进行制作。<br> 武器的原材料一般使用坚实的金、铁、玉、硬木等等。一个小时内可以累计做出1件武器。<br> 当你制作飞镖、小刀轻型投掷武器时，他们额外获得2点破甲，并将基础武器伤害提升至3L。<br> 当你制作投枪、投锤重型投掷武器时，他们额外获得2点威猛，并将基础武器伤害提升至3L。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',15)])])}const m=e(n,[["render",o]]);export{x as __pageData,m as default};
